mapper.select:
SELECT alarm_history_id AS alarmHistoryId, line_id AS lineId, alarm_code AS alarmCode, value, CASE WHEN read_at IS NULL THEN FALSE ELSE TRUE END AS isRead, created_at AS createdAt FROM ALARM_HISTORY WHERE line_id = #{lineId} AND deleted_at IS NULL
AND read_at IS NOT NULL
AND read_at IS NULL
AND alarm_code = #{code}
ORDER BY created_at DESC LIMIT #{size} OFFSET #{offset}
